const raw = $input.item.json;

if (!raw.email || typeof raw.email !== 'string') {
  return [];
}

const email = raw.email.trim().toLowerCase();

if (email.length === 0) {
  return [];
}

return [{
  json: {
    event_id: raw.event_id,
    session_id: raw.session_id,
    known_id: raw.known_id,
    created_at: raw.created_at,
    email: email,
    form_data: raw.form_data || {},
    risk_score: raw.risk_score || 0,
    risk_flags: raw.risk_flags || []
  }
}];

const raw = $input.item.json;
const { email, event_id } = raw;
const formData = raw.form_data || {};
const riskScore = raw.risk_score || 0;
const riskFlags = raw.risk_flags || [];

const name = formData.name || null;
const phone = formData.phone || null;

const SKIP = new Set(['email', 'formId', 'formAction', 'durationMs', 'behavioral_signals']);
const lines = Object.entries(formData)
  .filter(([k, v]) => !SKIP.has(k) && v !== null && v !== undefined && v !== '')
  .map(([k, v]) => `${k}: ${v}`);

let description = 'Lead capturado via Zentria Tracking SDK';
if (lines.length > 0) description += ' | ' + lines.join(' | ');
if (riskScore >= 2) {
  description += ' | REQUIRES REVIEW risk_score: ' + riskScore + ' flags: ' + riskFlags.join(', ');
}

const leadValues = {
  name: name || email,
  email_from: email,
  phone: phone || '',
  contact_name: name || '',
  description: description,
  type: 'lead',
};

const now = new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' });
const revisitNote = `<p><strong>Nuevo interés detectado</strong> — ${now}</p><p>El contacto volvió a mostrar interés a través del formulario de la landing.</p>${lines.length > 0 ? '<p>' + lines.join('<br/>') + '</p>' : ''}`;

const searchBody = JSON.stringify({
  jsonrpc: '2.0', method: 'call',
  params: {
    model: 'crm.lead', method: 'search_read',
    args: [[['email_from', '=', email]]],
    kwargs: { fields: ['id', 'email_from', 'name', 'priority'], limit: 1, context: {} }
  }
});

const createBody = JSON.stringify({
  jsonrpc: '2.0', method: 'call',
  params: {
    model: 'crm.lead', method: 'create',
    args: [[leadValues]],
    kwargs: { context: {} }
  }
});

return [{ json: { email, event_id, name, phone, riskScore, riskFlags, revisitNote, searchBody, createBody } }];
